"// Mapping logic to generate the PersonFirstName according to the following convention.
function generateLicensePlateRCN() {
    let licensePlateRCN = Person.Custom.kenteken;

    if (typeof licensePlateRCN !== 'undefined' && licensePlateRCN) {
        // Remove -
        licensePlateRCN = licensePlateRCN.replaceAll('-', '');

        // Add countrycode
        licensePlateRCN = 'NLD,' + licensePlateRCN;
        
        // Trim spaces at start and end
        licensePlateRCN = licensePlateRCN.trim();

        // Remove diacritical chars
        licensePlateRCN = deleteDiacriticalMarks(licensePlateRCN);
    }

    return licensePlateRCN;
}

generateLicensePlateRCN();"

"// Mapping logic to generate the PersonName according to the following convention.
// First choice	        B	van den boele
// 	                    BP	van den boele
// 	                    P	de Vries
// 	                    PB  van den boele
function generatePersonName() {
    let lastName = Person.Name.FamilyName;
    let lastNamePartner = Person.Name.FamilyNamePartner;

    let convention = Person.Name.Convention;

    let personName = '';
    switch (convention) {
        case "P":
            if (typeof lastNamePartner !== 'undefined' && lastNamePartner) {
                personName = personName + lastNamePartner;
            }
            break;
        case "B":
        default:
        if (typeof lastName !== 'undefined' && lastName) {
                personName = personName + lastName;
            }
            break;
    }
    if (typeof personName !== 'undefined' && personName) {
        // Trim spaces at start and end
        personName = personName.trim();

        // Remove diacritical chars
        personName = deleteDiacriticalMarks(personName);

        // Escape single quotes
        personName = personName.replace("'","\\'");
    }

    return personName;
}

generatePersonName();"

